package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

type Comment struct {
	Author string
	Body   template.HTML
	At     time.Time
}

var comments = []Comment{
	{
		Author: "alice",
		Body:   template.HTML("Hello <b>world</b>! This is <i>formatted</i>."),
		At:     time.Now().Add(-2 * time.Hour),
	},
	{
		Author: "bob",
		Body:   template.HTML(`I like <a href="https://golang.org">Go</a>.<br>New line here.`),
		At:     time.Now().Add(-30 * time.Minute),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!doctype html>
<html>
<head>
	<meta charset="utf-8">
	<title>Comments</title>
	<style>
		body { font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; margin: 2rem; }
		.comment { border: 1px solid #ddd; padding: 1rem; margin: 0 0 1rem 0; border-radius: 8px; }
		.meta { color: #666; font-size: 0.9rem; margin-bottom: 0.5rem; }
		.body { white-space: normal; }
	</style>
</head>
<body>
	<h1>User comments</h1>
	{{if .}}
		{{range .}}
			<div class="comment">
				<div class="meta">
					<strong>{{.Author}}</strong>
					<span> — {{.At.Format "2006-01-02 15:04:05"}}</span>
				</div>
				<div class="body">{{.Body}}</div>
			</div>
		{{end}}
	{{else}}
		<p>No comments yet.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "template error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}